var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR001L0004: <color=#ffd34c>양하림</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. WR001L0004：<color=#ffd34c>ホシノ・ウサギ</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR001L0004: <color=#ffd34c>Yang Harim</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. WR001L0004: <color=#ffd34c>楊夏琳</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하림이는 골목대장이었어요.","JPN":"ウサギは路地裏のボスでした。","ENG":"Harim was always the leader of the group.","TWN":"夏琳是這裡的孩子王。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"평범한 의미의 골목대장이 아니라...... 마을에 돌아다니던 동물들이 그 애를 엄청 따랐거든요.","JPN":"言葉通りの意味ではなく……町中の動物たちがあの子に懐いてたんです。","ENG":"And not just any ordinary leader. All of the animals in town really liked her.","TWN":"而且不是普通意義上的孩子王，就連遊蕩在村子裡的動物也很聽她的話。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"길고양이라던가 강아지라던가...... 하림이가 지나가기만 하면 모여들어서 주위를 맴돌았어요.","JPN":"野良猫や野良犬……ウサギが近くを通りかかると\\nどこからともなく彼女の周りに集まってくるんです。","ENG":"Such as stray cats and dogs... Whenever Harim passed by, they would all gather around her.","TWN":"不管是流浪貓還是狗……只要夏琳一經過，就會聚在她身邊，圍著她打轉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래서 또래 아이들에게도 인기가 많았죠. 그 나이 때에는 다들 동물을 좋아하니까요.","JPN":"だから、同世代の子たちからも人気が\\nありました。動物が好きな年頃でもありますからね。","ENG":"That's why she was so popular amongst her friends as well. Everyone at that age loves animals.","TWN":"所以她在同齡的小孩中也很有人氣，畢竟那個年齡的小孩，大家都喜歡動物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"좀 이상하단 생각은 들긴 했는데, 설마 하림이가 카운터일 줄은 몰랐죠.","JPN":"少しおかしいなとは思ったけど、まさか\\nウサギがカウンターだとは思いもしませんでした。","ENG":"It did seem weird at the time, we but had no idea Harim would be a Counter.","TWN":"雖然是覺得她有點怪，但誰知道夏琳竟然會是制裁者呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그걸 확신하게 된 계기가 있다면......","JPN":"でもそれを確信したきっかけが……","ENG":"If there's an incident that made us sure of that...","TWN":"確定她是制裁者的契機……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그래요. 동물원에서 이송하던 반달곰이 탈출했던 사건! 기억하세요?","JPN":"動物園から移送中だった\\nツキノワグマが脱出した事件です！　覚えてますか？","ENG":"Oh, that's right. There was that time the black bear escaped from the zoo while being transferred! Remember that?","TWN":"對了，動物園移送亞洲黑熊的逃跑事件！你記得嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"언론에선 경찰이 곰을 마취시켜 사건을 해결한 걸로 알고 있지만......","JPN":"メディアでは警察がクマに麻酔銃を\\n撃って事件を解決したことになっていますが……","ENG":"The media reported it as if the cops drugged the bear to capture it...","TWN":"雖然媒體說是警察麻醉了黑熊，才解決事件的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그게 전부는 아니에요.","JPN":"それがすべてではありません。","ENG":"But that's not all.","TWN":"但這不是事情的全部經過。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"시장에서 사람들을 습격하려던 곰을 얌전하게 만들었던 건 바로 하림이었거든요.","JPN":"市場で人々に襲いかかろうとしていた\\nクマをおとなしくさせたのはウサギなんです。","ENG":"It was actually Harim who calmed down the bear that was attacking people in the market.","TWN":"因為讓正要襲擊市場的熊安分下來的人，正是夏琳。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"쿠워어어어어!!!","JPN":"グオオオォ！！","ENG":"Rooooaar!","TWN":"吼吼吼吼吼吼！！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"떽!","JPN":"ほらほら！","ENG":"Hey!","TWN":"站住！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"자~ 착하지. 이런 곳에서 말썽부리면 안돼요.","JPN":"いい子でしょ？　こんな所で暴れちゃダメだよ！","ENG":"There, there. You shouldn't be causing trouble here.","TWN":"好～真乖。不可以在這種地方搗蛋喔。"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"뀨우웅...... 꾸웅......","JPN":"クウゥーン……クゥン……","ENG":"*Whimper* *Groan*","TWN":"嗷嗷嗚……嗷嗚……"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"옳지, 그래. 얌전히 있어야지.","JPN":"そうそう。おとなしくしてなきゃ！","ENG":"Good girl, yes. You need to behave.","TWN":"沒錯，做得很好。你得乖乖待著喔。"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"하, 학생! 얼른 떨어져! 그건 맹수야! 위험하다고!","JPN":"そ、そこの学生！　今すぐ離れるんだ！\\nそこにいるのは猛獣なんだぞ！","ENG":"K-kid! Get away from the bear! That's a beast! It's dangerous!","TWN":"同、同學！快點離開牠！那是猛獸啊！很危險的！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네? 하, 하지만 이렇게 착한데요? 말도 잘 듣고......","JPN":"はい？　で、でもいい子ですよ？　ちゃんと言うことも聞くし……","ENG":"Hmm? B-but she's a nice bear. She's a good listener, too...","TWN":"什麼？可、可是牠這麼乖啊？還很聽話……"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"무슨 소릴 하는 거야?! 곰이 사람 말을 어떻게 알아 들어? 잔말 말고 도망치라고!","JPN":"何を言っているんだ！　クマに人間の言うことがわかるわけないだろ！　いいから、今すぐ離れなさい！","ENG":"What are you saying?! Bears can't understand human language! Stop fooling around and run!","TWN":"妳在說什麼？！熊怎麼可能聽得懂人的話？別說廢話了，快逃啊！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"다들 발포 준비! 저 아이의 안전을 확보하는 즉시 곰을 사살한다!","JPN":"発砲準備！　学生の安全が確保でき次第、クマを射殺する！","ENG":"All units, prepare to engage! Shoot the bear as soon as we secure the child's safety!","TWN":"大家準備開火！一確保那個小朋友的安全，就立刻擊斃那隻熊！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네, 네? 설마 이 아이를 쏘실 거에요?","JPN":"えっ！？　まさか、この子を撃つんですか？","ENG":"W-what? Are you really going to shoot her?","TWN":"什、什麼？你們難道要對這孩子開槍嗎？"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"안타깝지만 어쩔 수 없어, 꼬마야! 이렇게 사람이 많은 곳에서 곰이 난동을 부리면 큰 사고가 날 거라고!","JPN":"心苦しいが仕方ないんだ。こんな人が多い所でクマが\\n暴れてしまえば、死傷者が出てしまうだろう？","ENG":"I know it's sad, but we have no choice, kid! If a bear starts attacking people in a place like this, it will be a huge disaster!","TWN":"雖然很遺憾但沒辦法，小朋友！如果熊在這種人多的地方大鬧的話，會發生很嚴重的事故的！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BEAR_EXTRA_NULL_NULL","text":{"KOREA":"크르릉......!!","JPN":"グルル……！","ENG":"Grrrr!!","TWN":"吼吼吼吼……！！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 안 돼요! 제가...... 제가 어떻게든 해 볼게요!","JPN":"そんなのダメです！　僕が……僕が何とかします！","ENG":"N-no! I'll... I'll do something about it!","TWN":"不！不可以！我……我會想辦法！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIELD_SL_NULL_POLICE","text":{"KOREA":"학생?! 뭐 하는 거야? 떨어지랬잖아?! 학생!!","JPN":"なっ、何をするつもりだ！？　危ないと言っているだろう！","ENG":"Kid?! What are you doing? I told you to back off! Kid!","TWN":"同學？！妳在做什麼？不是叫妳離開嗎？！同學！"},"stage":{"bg":"PARK","bgm":"THEMA_WHITERABBIT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그날 이후로 하림이는 카운터 각성 판정을 받고 관리국 아카데미 중등부로 전학을 가게 됐어요.","JPN":"その事件の後にウサギはカウンター覚醒判定を受け、\\n管理局カウンターアカデミーの中等部に転校することになりました。","ENG":"After that day, Harim was officially registered as a Counter and transferred to the Administration Junior High Academy.","TWN":"那天之後，夏琳受到制裁者覺醒判定，轉學到了管理局學院的國中部。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"동물들이 그토록 따르던 게 하림이가 카운터이기 때문이었다는 건 좀 놀랍긴 하지만......","JPN":"動物たちがあんなに懐いたのは、ウサギが\\nカウンターだったからと知って驚きましたが……","ENG":"It was surprising to find out that all of the animals loved Harim because she was a Counter...","TWN":"動物們會那樣跟著夏琳，是因為她是制裁者……我雖然對此有點驚訝……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"제 생각에는 그런 능력이 없었어도 그 애는 동물들과 얼마든지 친해질 수 있었을 거에요.","JPN":"多分そんな能力がなくても、動物と\\nいくらでも仲良くなれる子だっただろうなと思います。","ENG":"But in my opinion, she would have become friends with the animals even without her abilities.","TWN":"但我認為，就算沒有那種能力，那孩子不管怎麼樣，都能和動物們變得很要好。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......그래도 맹수들에게 함부로 가까이 가는 습관은 좀 고쳐야겠지만요.","JPN":"……でも猛獣に平気で近づく癖は直した方がいいですね。","ENG":"Although she should really fix her habit of recklessly approaching wild beasts.","TWN":"……但還是得改改那個隨便靠近猛獸的習慣。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"네? 그 곰은 어떻게 됐냐고요?","JPN":"あぁ、そのクマがどうなったかですか？","ENG":"Hmm? What happened to that bear?","TWN":"咦？你問熊的下場？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"글쎄요. 그때 빛이 번쩍이고 나서는 다들 기절해 버려서......","JPN":"実はその時ピカッと明るい光が\\n放たれて、みんな気絶してしまったんです……","ENG":"Who knows? There was a flash of light and everyone fainted...","TWN":"我不太清楚耶，當時有道光一閃，讓在場的所有人都暈過去了……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 후에 어떤 일이 벌어졌는지는 잘 모르겠어요.","JPN":"だからその後何が起きたかは、私もよくわからなくて……","ENG":"No one knows what happened after that.","TWN":"接下來就不知道發生什麼事了。"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"뉴스에서도 별다른 피해 없이 해결됐다는 식으로 두루뭉술하게만 보도되고......","JPN":"ニュースでも被害者を出すことなく、\\n無事解決したという感じで当たり障りなく報道されたので……","ENG":"Even the news just reported vaguely that there was no damage...","TWN":"新聞上也只說沒有出現任何傷亡，事情就解決了，報導得很是敷衍……"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아마도 무사히 포획해서 어딘가 좋은 곳에서 기르고 있지 않을까요?","JPN":"おそらく無事に捕獲されて、\\nもっと良い場所で飼育されていると思いますよ？","ENG":"I'm guessing it was captured and is being raised somewhere safe?","TWN":"大概在順利捕獲後，好好養在某個地方吧？"},"stage":{"bg":"PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};